-- OpenResty Lua access control script

local auth_tokens = {
  ["user1"] = "token1",
  ["user2"] = "token2"
}

local user_roles = {
  ["user1"] = "admin",
  ["user2"] = "user"
}

function check_permissions(ngx)
  -- Check if the request is for an admin endpoint
  if ngx.var.uri:find("/admin") or ngx.var.uri:find("/api") then
    return true
  end

  -- Extract the authentication token from the request headers
  local auth_token = ngx.req.get_headers()["Authorization"]

  -- Check if the authentication token is valid
  if not auth_tokens[auth_token] then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.say("Invalid authentication token")
    return false
  end

  -- Extract the user role from the request headers
  local user_role = user_roles[auth_token]

  -- Check if the user has the required permissions
  if not user_role or user_role == "user" then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Insufficient permissions")
    return false
  end

  return true
end